// ========== Repairs ==========
async function loadRepairs(page=1){const f=state.filters;let url=`/api/repairs?page=${page}&limit=15`;if(f.status)url+=`&status=${f.status}`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.repairs={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderRepairs(){const{data,page,total}=state.repairs;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Repairs</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewRepairModal()">+ New Repair</button></div></div><div class="filter-bar"><select onchange="state.filters.status=this.value;loadRepairs()"><option value="">All Status</option>${STATUSES.map(s=>`<option value="${s}"${state.filters.status===s?' selected':''}>${s.replace('_',' ')}</option>`).join('')}</select><input type="text" placeholder="Search..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadRepairs()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadRepairs()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Customer</th><th>Model</th><th>Status</th><th>Balance</th><th>Date</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(r=>`<tr><td>#${r.id}</td><td>${esc(r.customer_name||'-')}</td><td>${esc(r.model||'-')}</td><td><span class="badge ${STATUS_COLORS[r.status]||''}">${(r.status||'').replace('_',' ')}</span></td><td style="color:${r.balance>0?'var(--danger)':'var(--success)'}">${formatCurrency(r.balance)}</td><td>${formatDate(r.created_at)}</td><td><button class="btn btn-ghost btn-sm" onclick="showRepairDetail(${r.id})">View</button></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No repairs found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadRepairs(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadRepairs(${page+1})">Next</button></div>`;}
async function showRepairDetail(id){const r=await api(`/api/repairs/${id}`);if(!r.ok)return toast('Failed to load repair','error');const rp=r.data;const parts=rp.parts||[];const pays=rp.payments||[];const totalParts=rp.total_parts_cost||0;const totalPaid=rp.total_payments||0;const serviceFee=rp.service_fee||0;const grandTotal=totalParts+serviceFee;const balance=rp.balance||0;showModal(`<div class="modal-header"><h2>Repair #${rp.id}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><div class="detail-grid"><div class="detail-item"><div class="label">Customer</div><div class="value">${esc(rp.customer_name||'-')}</div></div><div class="detail-item"><div class="label">Model</div><div class="value">${esc(rp.model||'-')}</div></div><div class="detail-item"><div class="label">IMEI</div><div class="value">${esc(rp.imei||'-')}</div></div><div class="detail-item"><div class="label">Status</div><div class="value"><span class="badge ${STATUS_COLORS[rp.status]||''}">${(rp.status||'').replace('_',' ')}</span></div></div><div class="detail-item detail-full"><div class="label">Issues</div><div class="value">${esc(rp.issues||'-')}</div></div></div><div style="margin-top:20px"><div class="card-header"><h3>Parts Used</h3><button class="btn btn-ghost btn-sm" onclick="showAddPartModal(${rp.id})">+ Add Part</button></div><table><thead><tr><th>Part</th><th>Qty</th><th>Price</th></tr></thead><tbody>${parts.length?parts.map(p=>`<tr><td>${esc(p.part_name||'-')}</td><td>${p.qty}</td><td>${formatCurrency(p.selling_price)}</td></tr>`).join(''):'<tr><td colspan="3" class="empty">No parts</td></tr>'}</tbody></table></div><div style="margin-top:20px"><div class="card-header"><h3>Payments</h3><button class="btn btn-ghost btn-sm" onclick="showAddPaymentModal(${rp.id})">+ Add Payment</button></div><table><thead><tr><th>Amount</th><th>Method</th><th>Date</th></tr></thead><tbody>${pays.length?pays.map(p=>`<tr><td>${formatCurrency(p.amount)}</td><td>${esc(p.method||'-')}</td><td>${formatDate(p.paid_at)}</td></tr>`).join(''):'<tr><td colspan="3" class="empty">No payments</td></tr>'}</tbody></table></div><div style="margin-top:16px;padding:16px;background:var(--bg);border-radius:8px"><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="color:var(--text-muted)">Parts Total:</span><span>${formatCurrency(totalParts)}</span></div><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="color:var(--text-muted)">Service Fee:</span><span>${formatCurrency(serviceFee)}</span></div><div style="display:flex;justify-content:space-between;margin-bottom:8px;font-weight:600"><span>Grand Total:</span><span>${formatCurrency(grandTotal)}</span></div><div style="display:flex;justify-content:space-between;font-weight:700"><span>Balance Due:</span><span style="color:${balance>0?'var(--danger)':'var(--success)'}">${formatCurrency(balance)}</span></div></div><div style="margin-top:16px;display:flex;gap:8px"><button class="btn btn-ghost" onclick="hideModal()">Close</button></div></div>`);}
async function showNewRepairModal(){const cRes=await api('/api/customers?limit=100');const customers=cRes.ok?(cRes.data.items||[]):[];showModal(`<div class="modal-header"><h2>New Repair</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createRepair(event)"><div class="form-group"><label>Customer</label><select id="repairCustomer"><option value="">Walk-in</option>${customers.map(c=>`<option value="${c.id}">${esc(c.name)} - ${esc(c.phone)}</option>`).join('')}</select></div><div class="form-group"><label>Model *</label><input type="text" id="repairModel" required placeholder="e.g. iPhone 14 Pro"></div><div class="form-group"><label>Issues *</label><textarea id="repairIssues" required placeholder="Describe the problem"></textarea></div><div class="form-row"><div class="form-group"><label>IMEI</label><input type="text" id="repairImei" placeholder="Optional"></div><div class="form-group"><label>Service Fee</label><input type="number" step="0.01" id="repairFee" value="0"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createRepair(e){e.preventDefault();const r=await api('/api/repairs',{method:'POST',body:JSON.stringify({customer_id:document.getElementById('repairCustomer').value||undefined,model:document.getElementById('repairModel').value,issues:document.getElementById('repairIssues').value,imei:document.getElementById('repairImei').value,service_fee:parseFloat(document.getElementById('repairFee').value)||0})});if(r.ok){toast('Repair created','success');hideModal();loadRepairs();}else toast(r.data.error||'Failed','error');}
async function showAddPartModal(repairId){const r=await api('/api/parts?limit=100');const parts=r.ok?(r.data.items||[]):[];showModal(`<div class="modal-header"><h2>Add Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="addPart(event,${repairId})"><div class="form-group"><label>Part *</label><select id="addPartId" required><option value="">Select part</option>${parts.filter(p=>p.stock_qty>0).map(p=>`<option value="${p.id}">${esc(p.name)} (Stock: ${p.stock_qty}) - ${formatCurrency(p.selling_price)}</option>`).join('')}</select></div><div class="form-row"><div class="form-group"><label>Qty *</label><input type="number" id="addPartQty" value="1" min="1" required></div><div class="form-group"><label>Selling Price</label><input type="number" step="0.01" id="addPartPrice" placeholder="Auto from part"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add</button></div></form></div>`);}
async function addPart(e,repairId){e.preventDefault();const partId=document.getElementById('addPartId').value;const qty=document.getElementById('addPartQty').value;const price=document.getElementById('addPartPrice').value||0;const r=await api(`/api/repairs/${repairId}/parts?part_id=${partId}&qty=${qty}&selling_price=${price}`,{method:'POST'});if(r.ok){toast('Part added','success');hideModal();showRepairDetail(repairId);loadRepairs();}else toast(r.data.error||'Failed','error');}
async function showAddPaymentModal(repairId){showModal(`<div class="modal-header"><h2>Add Payment</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="addPayment(event,${repairId})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="payAmount" required></div><div class="form-group"><label>Method *</label><select id="payMethod" required><option value="">Select</option>${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div></div><div class="form-group"><label>Notes</label><input type="text" id="payNotes" placeholder="Optional"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record</button></div></form></div>`);}
async function addPayment(e,repairId){e.preventDefault();const r=await api('/api/payments',{method:'POST',body:JSON.stringify({repair_id:repairId,amount:parseFloat(document.getElementById('payAmount').value),method:document.getElementById('payMethod').value,notes:document.getElementById('payNotes').value||''})});if(r.ok){toast('Payment recorded','success');hideModal();showRepairDetail(repairId);loadRepairs();}else toast(r.data.error||'Failed','error');}

// ========== Customers ==========
async function loadCustomers(page=1){const f=state.filters;let url=`/api/customers?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.customers={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderCustomers(){const{data,page,total}=state.customers;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Customers</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewCustomerModal()">+ New Customer</button></div></div><div class="filter-bar"><input type="text" placeholder="Search name or phone..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadCustomers()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadCustomers()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Phone</th><th>Email</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(c=>`<tr><td>#${c.id}</td><td>${esc(c.name)}</td><td>${esc(c.phone||'-')}</td><td>${esc(c.email||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditCustomerModal(${c.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteCustomer(${c.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="5" class="empty">No customers</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadCustomers(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadCustomers(${page+1})">Next</button></div>`;}
async function showNewCustomerModal(){showModal(`<div class="modal-header"><h2>New Customer</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createCustomer(event)"><div class="form-group"><label>Name *</label><input type="text" id="custName" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="custPhone"></div><div class="form-group"><label>Email</label><input type="email" id="custEmail"></div></div><div class="form-group"><label>Address</label><input type="text" id="custAddress"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createCustomer(e){e.preventDefault();const r=await api('/api/customers',{method:'POST',body:JSON.stringify({name:document.getElementById('custName').value,phone:document.getElementById('custPhone').value,email:document.getElementById('custEmail').value,address:document.getElementById('custAddress').value})});if(r.ok){toast('Customer created','success');hideModal();loadCustomers();}else toast(r.data.error||'Failed','error');}
async function showEditCustomerModal(id){const r=await api(`/api/customers/${id}`);if(!r.ok)return toast('Failed','error');const c=r.data;showModal(`<div class="modal-header"><h2>Edit Customer</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateCustomer(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="custName" value="${esc(c.name)}" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="custPhone" value="${esc(c.phone||'')}"></div><div class="form-group"><label>Email</label><input type="email" id="custEmail" value="${esc(c.email||'')}"></div></div><div class="form-group"><label>Address</label><input type="text" id="custAddress" value="${esc(c.address||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateCustomer(e,id){e.preventDefault();const r=await api(`/api/customers/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('custName').value,phone:document.getElementById('custPhone').value,email:document.getElementById('custEmail').value,address:document.getElementById('custAddress').value})});if(r.ok){toast('Customer updated','success');hideModal();loadCustomers(state.customers.page);}else toast(r.data.error||'Failed','error');}
async function deleteCustomer(id){if(!confirm('Delete this customer?'))return;const r=await api(`/api/customers/${id}`,{method:'DELETE'});if(r.ok){toast('Customer deleted','success');loadCustomers(state.customers.page);}else toast(r.data.error||'Failed','error');}

// ========== Parts ==========
async function loadParts(page=1){const f=state.filters;let url=`/api/parts?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.parts={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderParts(){const{data,page,total}=state.parts;const pages=Math.ceil(total/15)||1;const lowStock=data.filter(p=>p.stock_qty<=p.min_stock_alert);return`<div class="topbar"><h1>Inventory</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewPartModal()">+ Add Part</button></div></div>${lowStock.length?`<div style="background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:8px;padding:12px 16px;margin-bottom:16px;color:var(--danger);font-size:13px">Warning: ${lowStock.length} part(s) below minimum stock</div>`:''}<div class="filter-bar"><input type="text" placeholder="Search parts..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadParts()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadParts()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>SKU</th><th>Name</th><th>Stock</th><th>Unit Price</th><th>Sell Price</th><th>Status</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(p=>`<tr><td>#${p.id}</td><td>${esc(p.sku||'-')}</td><td>${esc(p.name)}</td><td>${p.stock_qty}</td><td>${formatCurrency(p.unit_price)}</td><td>${formatCurrency(p.selling_price)}</td><td><span class="badge ${p.stock_qty<=p.min_stock_alert?'badge-low':'badge-ok'}">${p.stock_qty<=p.min_stock_alert?'LOW':'OK'}</span></td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditPartModal(${p.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deletePart(${p.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="8" class="empty">No parts</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadParts(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadParts(${page+1})">Next</button></div>`;}
async function showNewPartModal(){showModal(`<div class="modal-header"><h2>Add Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createPart(event)"><div class="form-group"><label>Name *</label><input type="text" id="partName" required></div><div class="form-row"><div class="form-group"><label>Stock *</label><input type="number" id="partStock" value="0" min="0" required></div><div class="form-group"><label>Min Alert</label><input type="number" id="partMinStock" value="5" min="0"></div></div><div class="form-row"><div class="form-group"><label>Unit Cost *</label><input type="number" step="0.01" id="partPrice" required></div><div class="form-group"><label>Sell Price *</label><input type="number" step="0.01" id="partSellPrice" required></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Part</button></div></form></div>`);}
async function createPart(e){e.preventDefault();const r=await api('/api/parts',{method:'POST',body:JSON.stringify({name:document.getElementById('partName').value,stock_qty:parseInt(document.getElementById('partStock').value),min_stock_alert:parseInt(document.getElementById('partMinStock').value),unit_price:parseFloat(document.getElementById('partPrice').value),selling_price:parseFloat(document.getElementById('partSellPrice').value)})});if(r.ok){toast('Part added','success');hideModal();loadParts();}else toast(r.data.error||'Failed','error');}
async function showEditPartModal(id){const r=await api(`/api/parts/${id}`);if(!r.ok)return toast('Failed','error');const p=r.data;showModal(`<div class="modal-header"><h2>Edit Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updatePart(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="partName" value="${esc(p.name)}" required></div><div class="form-row"><div class="form-group"><label>Stock</label><input type="number" id="partStock" value="${p.stock_qty}" min="0"></div><div class="form-group"><label>Min Alert</label><input type="number" id="partMinStock" value="${p.min_stock_alert}" min="0"></div></div><div class="form-row"><div class="form-group"><label>Unit Cost</label><input type="number" step="0.01" id="partPrice" value="${p.unit_price}"></div><div class="form-group"><label>Sell Price</label><input type="number" step="0.01" id="partSellPrice" value="${p.selling_price}"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updatePart(e,id){e.preventDefault();const r=await api(`/api/parts/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('partName').value,stock_qty:parseInt(document.getElementById('partStock').value),min_stock_alert:parseInt(document.getElementById('partMinStock').value),unit_price:parseFloat(document.getElementById('partPrice').value),selling_price:parseFloat(document.getElementById('partSellPrice').value)})});if(r.ok){toast('Part updated','success');hideModal();loadParts(state.parts.page);}else toast(r.data.error||'Failed','error');}
async function deletePart(id){if(!confirm('Delete this part?'))return;const r=await api(`/api/parts/${id}`,{method:'DELETE'});if(r.ok){toast('Part deleted','success');loadParts(state.parts.page);}else toast(r.data.error||'Failed','error');}

// ========== Payments ==========
async function loadPayments(page=1){const f=state.filters;let url=`/api/payments?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;const r=await api(url);if(r.ok){state.payments={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderPayments(){const{data,page,total}=state.payments;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Payments</h1></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadPayments()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadPayments()"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadPayments()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Repair#</th><th>Amount</th><th>Method</th><th>Date</th></tr></thead><tbody>${data.length?data.map(p=>`<tr><td>#${p.id}</td><td>${p.repair_id?'#'+p.repair_id:'-'}</td><td>${formatCurrency(p.amount,p.currency)}</td><td>${esc(p.method||'-')}</td><td>${formatDate(p.paid_at)}</td></tr>`).join(''):'<tr><td colspan="5" class="empty">No payments</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadPayments(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadPayments(${page+1})">Next</button></div>`;}

// ========== Expenses ==========
async function loadExpenses(page=1){const f=state.filters;let url=`/api/expenses?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;const[catRes]=await Promise.all([api('/api/expenses/categories')]);if(catRes.ok)state.expense_categories=Array.isArray(catRes.data)?catRes.data:[];const r=await api(url);if(r.ok){state.expenses={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderExpenses(){const{data,page,total}=state.expenses;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Expenses</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewExpenseModal()">+ Add Expense</button></div></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadExpenses()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadExpenses()"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadExpenses()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Category</th><th>Amount</th><th>Note</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(x=>`<tr><td>#${x.id}</td><td>${formatDate(x.date)}</td><td>${esc(x.category_name||'-')}</td><td>${formatCurrency(x.amount,x.currency)}</td><td>${esc(x.note||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditExpenseModal(${x.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteExpense(${x.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="6" class="empty">No expenses</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadExpenses(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadExpenses(${page+1})">Next</button></div>`;}
async function showNewExpenseModal(){showModal(`<div class="modal-header"><h2>Add Expense</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createExpense(event)"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="expAmt" required></div><div class="form-group"><label>Category *</label><select id="expCat" required><option value="">Select</option>${(state.expense_categories||[]).map(c=>`<option value="${c.id}">${esc(c.name)}</option>`).join('')}</select></div></div><div class="form-group"><label>Date</label><input type="date" id="expDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="expNote" placeholder="Description"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add</button></div></form></div>`);}
async function createExpense(e){e.preventDefault();const r=await api('/api/expenses',{method:'POST',body:JSON.stringify({amount:parseFloat(document.getElementById('expAmt').value),category_id:parseInt(document.getElementById('expCat').value),date:document.getElementById('expDate').value,note:document.getElementById('expNote').value})});if(r.ok){toast('Expense added','success');hideModal();loadExpenses();}else toast(r.data.error||'Failed','error');}
async function showEditExpenseModal(id){const r=await api(`/api/expenses/${id}`);if(!r.ok)return toast('Failed','error');const x=r.data;showModal(`<div class="modal-header"><h2>Edit Expense</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateExpense(event,${id})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="expAmt" value="${x.amount}" required></div><div class="form-group"><label>Category *</label><select id="expCat" required>${(state.expense_categories||[]).map(c=>`<option value="${c.id}"${c.id==x.category_id?' selected':''}>${esc(c.name)}</option>`).join('')}</select></div></div><div class="form-group"><label>Note</label><input type="text" id="expNote" value="${esc(x.note||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateExpense(e,id){e.preventDefault();const r=await api(`/api/expenses/${id}`,{method:'PUT',body:JSON.stringify({amount:parseFloat(document.getElementById('expAmt').value),category_id:parseInt(document.getElementById('expCat').value),note:document.getElementById('expNote').value})});if(r.ok){toast('Expense updated','success');hideModal();loadExpenses(state.expenses.page);}else toast(r.data.error||'Failed','error');}
async function deleteExpense(id){if(!confirm('Delete this expense?'))return;const r=await api(`/api/expenses/${id}`,{method:'DELETE'});if(r.ok){toast('Expense deleted','success');loadExpenses(state.expenses.page);}else toast(r.data.error||'Failed','error');}

// ========== Daily Sales ==========
async function loadDailySales(page=1){const f=state.filters;let url=`/api/daily-sales?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;const r=await api(url);if(r.ok){state.daily_sales={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderDailySales(){const{data,page,total}=state.daily_sales;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Daily Sales</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewDailySaleModal()">+ Add Entry</button></div></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadDailySales()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadDailySales()"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadDailySales()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Amount</th><th>Category</th><th>Note</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${formatDate(s.date)}</td><td>${formatCurrency(s.amount,s.currency)}</td><td>${esc(s.category||'-')}</td><td>${esc(s.note||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditDailySaleModal(${s.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteDailySale(${s.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="6" class="empty">No entries</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadDailySales(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadDailySales(${page+1})">Next</button></div>`;}
async function showNewDailySaleModal(){showModal(`<div class="modal-header"><h2>Add Sales Entry</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createDailySale(event)"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="saleAmt" required></div><div class="form-group"><label>Category</label><input type="text" id="saleCat" placeholder="e.g. Accessories"></div></div><div class="form-group"><label>Date</label><input type="date" id="saleDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="saleNote" placeholder="Description"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add</button></div></form></div>`);}
async function createDailySale(e){e.preventDefault();const r=await api('/api/daily-sales',{method:'POST',body:JSON.stringify({amount:parseFloat(document.getElementById('saleAmt').value),category:document.getElementById('saleCat').value,date:document.getElementById('saleDate').value,note:document.getElementById('saleNote').value})});if(r.ok){toast('Entry added','success');hideModal();loadDailySales();}else toast(r.data.error||'Failed','error');}
async function showEditDailySaleModal(id){const r=await api(`/api/daily-sales/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Sales Entry</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateDailySale(event,${id})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="saleAmt" value="${s.amount}" required></div><div class="form-group"><label>Category</label><input type="text" id="saleCat" value="${esc(s.category||'')}"></div></div><div class="form-group"><label>Note</label><input type="text" id="saleNote" value="${esc(s.note||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateDailySale(e,id){e.preventDefault();const r=await api(`/api/daily-sales/${id}`,{method:'PUT',body:JSON.stringify({amount:parseFloat(document.getElementById('saleAmt').value),category:document.getElementById('saleCat').value,note:document.getElementById('saleNote').value})});if(r.ok){toast('Entry updated','success');hideModal();loadDailySales(state.daily_sales.page);}else toast(r.data.error||'Failed','error');}
async function deleteDailySale(id){if(!confirm('Delete this entry?'))return;const r=await api(`/api/daily-sales/${id}`,{method:'DELETE'});if(r.ok){toast('Entry deleted','success');loadDailySales(state.daily_sales.page);}else toast(r.data.error||'Failed','error');}

// ========== Suppliers ==========
async function loadSuppliers(page=1){const f=state.filters;let url=`/api/suppliers?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.suppliers={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderSuppliers(){const{data,page,total}=state.suppliers;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Suppliers</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewSupplierModal()">+ Add Supplier</button></div></div><div class="filter-bar"><input type="text" placeholder="Search..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadSuppliers()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadSuppliers()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Phone</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${esc(s.name)}</td><td>${esc(s.phone||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditSupplierModal(${s.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteSupplier(${s.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="4" class="empty">No suppliers</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadSuppliers(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadSuppliers(${page+1})">Next</button></div>`;}
async function showNewSupplierModal(){showModal(`<div class="modal-header"><h2>Add Supplier</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createSupplier(event)"><div class="form-group"><label>Name *</label><input type="text" id="supName" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="supPhone"></div><div class="form-group"><label>Address</label><input type="text" id="supAddress"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createSupplier(e){e.preventDefault();const r=await api('/api/suppliers',{method:'POST',body:JSON.stringify({name:document.getElementById('supName').value,phone:document.getElementById('supPhone').value,address:document.getElementById('supAddress').value})});if(r.ok){toast('Supplier created','success');hideModal();loadSuppliers();}else toast(r.data.error||'Failed','error');}
async function showEditSupplierModal(id){const r=await api(`/api/suppliers/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Supplier</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateSupplier(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="supName" value="${esc(s.name)}" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="supPhone" value="${esc(s.phone||'')}"></div><div class="form-group"><label>Address</label><input type="text" id="supAddress" value="${esc(s.address||'')}"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateSupplier(e,id){e.preventDefault();const r=await api(`/api/suppliers/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('supName').value,phone:document.getElementById('supPhone').value,address:document.getElementById('supAddress').value})});if(r.ok){toast('Supplier updated','success');hideModal();loadSuppliers(state.suppliers.page);}else toast(r.data.error||'Failed','error');}
async function deleteSupplier(id){if(!confirm('Delete this supplier?'))return;const r=await api(`/api/suppliers/${id}`,{method:'DELETE'});if(r.ok){toast('Supplier deleted','success');loadSuppliers(state.suppliers.page);}else toast(r.data.error||'Failed','error');}

// ========== Purchase Orders ==========
async function loadPurchaseOrders(page=1){const f=state.filters;let url=`/api/purchase-orders?page=${page}&limit=15`;if(f.status)url+=`&status=${f.status}`;const r=await api(url);if(r.ok){state.purchase_orders={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderPurchaseOrders(){const{data,page,total}=state.purchase_orders;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Purchase Orders</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewPOModal()">+ New PO</button></div></div><div class="filter-bar"><select onchange="state.filters.status=this.value;loadPurchaseOrders()"><option value="">All Status</option>${PO_STATUSES.map(s=>`<option value="${s}"${state.filters.status===s?' selected':''}>${s.replace('_',' ')}</option>`).join('')}</select><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadPurchaseOrders()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>PO#</th><th>Supplier</th><th>Status</th><th>Total</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(po=>`<tr><td>#${po.id}</td><td>${esc(po.po_number)}</td><td>${esc(po.supplier_name||'-')}</td><td><span class="badge ${PO_STATUS_COLORS[po.status]||''}">${(po.status||'').replace('_',' ')}</span></td><td>${formatCurrency(po.total)}</td><td><button class="btn btn-ghost btn-sm" onclick="showPODetail(${po.id})">View</button></td></tr>`).join(''):'<tr><td colspan="6" class="empty">No POs</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadPurchaseOrders(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadPurchaseOrders(${page+1})">Next</button></div>`;}
let poItems=[];
async function showNewPOModal(){poItems=[{part_name:'',qty:1,cost:0,selling_price:0}];const sRes=await api('/api/suppliers?limit=100');const suppliers=sRes.ok?(sRes.data.items||[]):[];showModal(`<div class="modal-header"><h2>New Purchase Order</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createPO(event)"><div class="form-group"><label>Supplier *</label><select id="poSupplier" required><option value="">Select</option>${suppliers.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select></div><div id="poItemList">${poItems.map((it,i)=>`<div style="display:grid;grid-template-columns:2fr 1fr 1fr auto;gap:8px;margin-bottom:8px"><input type="text" placeholder="Part name" onchange="poItems[${i}].part_name=this.value" required><input type="number" value="${it.qty}" min="1" onchange="poItems[${i}].qty=Number(this.value)" required><input type="number" step="0.01" value="${it.cost}" onchange="poItems[${i}].cost=Number(this.value)" required><button type="button" class="btn btn-danger btn-sm" onclick="poItems.splice(${i},1);showNewPOModal()">X</button></div>`).join('')}</div><button type="button" class="btn btn-ghost btn-sm" onclick="poItems.push({part_name:'',qty:1,cost:0,selling_price:0});showNewPOModal()">+ Add Item</button><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create PO</button></div></form></div>`);}
async function createPO(e){e.preventDefault();const r=await api('/api/purchase-orders',{method:'POST',body:JSON.stringify({supplier_id:parseInt(document.getElementById('poSupplier').value),items:poItems.filter(it=>it.part_name)})});if(r.ok){toast('PO created','success');hideModal();loadPurchaseOrders();}else toast(r.data.error||'Failed','error');}
async function showPODetail(id){const r=await api(`/api/purchase-orders/${id}`);if(!r.ok)return toast('Failed','error');const po=r.data;const items=po.items||[];showModal(`<div class="modal-header"><h2>PO ${esc(po.po_number)}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><div class="detail-grid"><div class="detail-item"><div class="label">Status</div><div class="value"><span class="badge ${PO_STATUS_COLORS[po.status]||''}">${(po.status||'').replace('_',' ')}</span></div></div><div class="detail-item"><div class="label">Supplier</div><div class="value">${esc(po.supplier_name||'-')}</div></div><div class="detail-item"><div class="label">Total</div><div class="value">${formatCurrency(po.total)}</div></div><div class="detail-item"><div class="label">Payment Type</div><div class="value">${esc(po.payment_type)}</div></div></div><div style="margin-top:20px"><h3 style="font-size:14px;margin-bottom:12px">Items</h3><table><thead><tr><th>Part</th><th>Qty</th><th>Cost</th><th>Subtotal</th></tr></thead><tbody>${items.map(it=>`<tr><td>${esc(it.part_name||'-')}</td><td>${it.qty}</td><td>${formatCurrency(it.cost)}</td><td>${formatCurrency(it.cost*it.qty)}</td></tr>`).join('')}</tbody></table></div><div style="margin-top:16px;display:flex;gap:8px">${po.status==='draft'?`<button class="btn btn-primary" onclick="sendPO(${po.id})">Send to Supplier</button>`:''}${['draft','sent'].includes(po.status)?`<button class="btn btn-success" onclick="receivePO(${po.id})">Receive</button>`:''}</div></div>`);}
async function sendPO(id){const r=await api(`/api/purchase-orders/${id}/status`,{method:'PUT',body:JSON.stringify({status:'sent'})});if(r.ok){toast('PO sent','success');showPODetail(id);}else toast(r.data.error||'Failed','error');}
async function receivePO(id){const r=await api(`/api/purchase-orders/${id}`);if(!r.ok)return;const items=(r.data.items||[]).map(it=>({po_item_id:it.id,qty_received:it.qty,cost_price:it.cost}));const r2=await api(`/api/purchase-orders/${id}/receive`,{method:'POST',body:JSON.stringify({items})});if(r2.ok){toast('Shipment received','success');hideModal();loadPurchaseOrders();}else toast(r2.data.error||'Failed','error');}

// ========== Cash Till ==========
async function loadCashLedger(){const r=await api('/api/cash-ledger?limit=50');if(r.ok){state.cash_ledger={data:r.data.items||[],page:r.data.page||1,total:r.data.total||0};}const s=await api('/api/cash-ledger/summary');if(s.ok)state.cash_summary=s.data;const b=await api('/api/cash-ledger/balance');if(b.ok)state.cash_balance=b.data;render();}
function renderCashTill(){const{data}=state.cash_ledger;const summary=state.cash_summary||{};const balance=state.cash_balance||{};return`<div class="topbar"><h1>Cash Till</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showManualCashEntry()">+ Manual Entry</button></div></div><div class="stats-grid"><div class="stat-card green"><div class="stat-label">Cash In</div><div class="stat-value">${formatCurrency(summary.total_in||0)}</div></div><div class="stat-card red"><div class="stat-label">Cash Out</div><div class="stat-value">${formatCurrency(summary.total_out||0)}</div></div><div class="stat-card blue"><div class="stat-label">Net Balance</div><div class="stat-value">${formatCurrency(balance.balance||0)}</div></div><div class="stat-card cyan"><div class="stat-label">Transactions</div><div class="stat-value">${summary.count||0}</div></div></div>${summary.by_type?`<div class="card"><div class="card-header"><h3>By Type</h3></div><table><thead><tr><th>Type</th><th>Amount</th></tr></thead><tbody>${Object.entries(summary.by_type).map(([k,v])=>`<tr><td>${esc(k)}</td><td>${formatCurrency(v)}</td></tr>`).join('')}</tbody></table></div>`:''}<div class="card"><div class="card-header"><h3>Recent Transactions</h3></div><div class="table-wrap"><table><thead><tr><th>Date</th><th>Type</th><th>Direction</th><th>Amount</th><th>Method</th><th>Note</th></tr></thead><tbody>${data.length?data.map(r=>`<tr><td>${formatDate(r.date)}</td><td>${esc(r.type)}</td><td><span class="badge ${r.direction==='IN'?'badge-ok':'badge-low'}">${r.direction}</span></td><td>${formatCurrency(r.amount,r.currency)}</td><td>${esc(r.payment_method)}</td><td>${esc(r.note||'-')}</td></tr>`).join(''):'<tr><td colspan="6" class="empty">No transactions</td></tr>'}</tbody></table></div></div>`;}
async function showManualCashEntry(){showModal(`<div class="modal-header"><h2>Manual Cash Entry</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createManualCashEntry(event)"><div class="form-row"><div class="form-group"><label>Direction *</label><select id="clDir" required><option value="IN">Cash In</option><option value="OUT">Cash Out</option></select></div><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="clAmt" required></div></div><div class="form-row"><div class="form-group"><label>Type *</label><select id="clType" required><option value="manual_in">Manual In</option><option value="manual_out">Manual Out</option><option value="other">Other</option></select></div><div class="form-group"><label>Method</label><select id="clMethod">${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div></div><div class="form-group"><label>Date</label><input type="date" id="clDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="clNote" placeholder="Description"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record</button></div></form></div>`);}
async function createManualCashEntry(e){e.preventDefault();const r=await api('/api/cash-ledger',{method:'POST',body:JSON.stringify({date:document.getElementById('clDate').value,type:document.getElementById('clType').value,direction:document.getElementById('clDir').value,amount:parseFloat(document.getElementById('clAmt').value),payment_method:document.getElementById('clMethod').value,note:document.getElementById('clNote').value})});if(r.ok){toast('Entry recorded','success');hideModal();loadCashLedger();}else toast(r.data.error||'Failed','error');}

// ========== Dues ==========
async function loadDues(){const r=await api('/api/due-collections/balances');if(r.ok){state.due_balances=Array.isArray(r.data)?r.data:[];}const p=await api('/api/due-collections?limit=50');if(p.ok){state.due_collections={data:p.data.items||[],page:1,total:p.data.total||0};}render();}
function renderDues(){const balances=state.due_balances||[];const{data}=state.due_collections||{};return`<div class="topbar"><h1>Dues (Accounts Receivable)</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showRecordDueModal()">+ Record Due Payment</button></div></div><div class="card"><div class="card-header"><h3>Outstanding Balances</h3></div><div class="table-wrap"><table><thead><tr><th>Customer</th><th>Total Owed</th><th>Total Paid</th><th>Balance</th></tr></thead><tbody>${balances.length?balances.map(b=>`<tr><td>${esc(b.customer_name)}</td><td>${formatCurrency(b.total_owed)}</td><td style="color:var(--success)">${formatCurrency(b.total_paid)}</td><td style="color:${b.balance>0?'var(--danger)':'var(--success)'};font-weight:600">${formatCurrency(b.balance)}</td></tr>`).join(''):'<tr><td colspan="4" class="empty">No outstanding balances</td></tr>'}</tbody></table></div></div><div class="card"><div class="card-header"><h3>Recent Due Payments</h3></div><div class="table-wrap"><table><thead><tr><th>Date</th><th>Customer</th><th>Amount</th><th>Method</th><th>Note</th></tr></thead><tbody>${(data||[]).length?(data||[]).map(d=>`<tr><td>${formatDate(d.date)}</td><td>${esc(d.customer_name||'-')}</td><td style="color:var(--success)">${formatCurrency(d.amount,d.currency)}</td><td>${esc(d.method)}</td><td>${esc(d.note||'-')}</td></tr>`).join(''):'<tr><td colspan="5" class="empty">No due payments recorded</td></tr>'}</tbody></table></div></div>`;}
async function showRecordDueModal(){const cRes=await api('/api/customers?limit=100');const customers=cRes.ok?(cRes.data.items||[]):[];showModal(`<div class="modal-header"><h2>Record Due Payment</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createDuePayment(event)"><div class="form-group"><label>Customer *</label><select id="dueCust" required><option value="">Select customer</option>${customers.map(c=>`<option value="${c.id}">${esc(c.name)} - ${esc(c.phone)}</option>`).join('')}</select></div><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="dueAmt" required></div><div class="form-group"><label>Method *</label><select id="dueMethod" required><option value="">Select</option>${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div></div><div class="form-group"><label>Date</label><input type="date" id="dueDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="dueNote" placeholder="Optional"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record</button></div></form></div>`);}
async function createDuePayment(e){e.preventDefault();const r=await api('/api/due-collections',{method:'POST',body:JSON.stringify({customer_id:parseInt(document.getElementById('dueCust').value),amount:parseFloat(document.getElementById('dueAmt').value),method:document.getElementById('dueMethod').value,date:document.getElementById('dueDate').value,note:document.getElementById('dueNote').value})});if(r.ok){toast('Due payment recorded','success');hideModal();loadDues();}else toast(r.data.error||'Failed','error');}

// ========== Reports ==========
async function loadReports(){const r=await api('/api/reports/daily');if(r.ok)state.reports.daily=r.data;const m=await api('/api/reports/monthly');if(m.ok)state.reports.monthly=m.data;const pl=await api('/api/reports/profit-loss');if(pl.ok)state.reports.profit_loss=pl.data;render();}
function renderReports(){const d=state.reports.daily||{};const m=state.reports.monthly||{};const pl=state.reports.profit_loss||{};return`<div class="topbar"><h1>Reports</h1></div><div class="stats-grid"><div class="stat-card green"><div class="stat-label">Today's Revenue</div><div class="stat-value">${formatCurrency(d.total_revenue)}</div></div><div class="stat-card red"><div class="stat-label">Today's Expenses</div><div class="stat-value">${formatCurrency(d.total_expenses)}</div></div><div class="stat-card blue"><div class="stat-label">Today's Net</div><div class="stat-value">${formatCurrency(d.net_profit)}</div></div><div class="stat-card cyan"><div class="stat-label">Monthly Revenue</div><div class="stat-value">${formatCurrency(m.total_revenue)}</div></div><div class="stat-card purple"><div class="stat-label">Monthly Net</div><div class="stat-value">${formatCurrency(m.net_profit)}</div></div></div><div class="card"><div class="card-header"><h3>Profit/Loss (Last 30 Days)</h3></div><div class="table-wrap"><table><thead><tr><th>Date</th><th>Revenue</th><th>Expenses</th><th>Net</th></tr></thead><tbody>${(pl.items||[]).length?(pl.items||[]).slice(-14).map(i=>`<tr><td>${formatDate(i.date)}</td><td style="color:var(--success)">${formatCurrency(i.revenue)}</td><td style="color:var(--danger)">${formatCurrency(i.expenses)}</td><td style="font-weight:600;color:${i.net>=0?'var(--success)':'var(--danger)'}">${formatCurrency(i.net)}</td></tr>`).join(''):'<tr><td colspan="4" class="empty">No data</td></tr>'}</tbody></table></div></div>`;}

// ========== Settings ==========
async function loadSettingsPage(){const r=await api('/api/settings');if(r.ok)state.settings={...state.settings,...r.data};render();}
function renderSettings(){const s=state.settings;return`<div class="topbar"><h1>Settings</h1></div><div class="card" style="max-width:600px"><form onsubmit="saveSettings(event)"><div class="form-group"><label>Shop Name</label><input type="text" id="setShopName" value="${esc(s.shop_name||'')}"></div><div class="form-group"><label>Address</label><input type="text" id="setAddress" value="${esc(s.shop_address||'')}"></div><div class="form-group"><label>Phone</label><input type="text" id="setPhone" value="${esc(s.shop_phone||'')}"></div><div class="form-group"><label>Default Currency</label><select id="setCurrency">${CURRENCIES.map(c=>`<option value="${c}"${c===(s.default_currency||'USD')?' selected':''}>${c}</option>`).join('')}</select></div><button type="submit" class="btn btn-primary">Save Settings</button></form></div>`;}
async function saveSettings(e){e.preventDefault();const r=await api('/api/settings',{method:'PUT',body:JSON.stringify({shop_name:document.getElementById('setShopName').value,shop_address:document.getElementById('setAddress').value,shop_phone:document.getElementById('setPhone').value,default_currency:document.getElementById('setCurrency').value})});if(r.ok){toast('Settings saved','success');await loadSettings();render();}else toast(r.data.error||'Failed','error');}
